import { NextResponse } from 'next/server';

export async function POST(request) {
  try {
    // Parse the request body
    const body = await request.json();
    const { number } = body;

    // Validate the required field
    if (!number) {
      return NextResponse.json(
        { error: 'NIN number is required' },
        { status: 400 }
      );
    }

    // Get environment variables
    const appId = process.env.PREMBLY_APP_ID;
    const apiKey = process.env.PREMBLY_API_KEY;

    // Validate environment variables
    if (!appId || !apiKey) {
      return NextResponse.json(
        { error: 'Server configuration error: Missing API credentials' },
        { status: 500 }
      );
    }

    // Make request to Prembly API
    const premblyResponse = await fetch('https://api.prembly.com/api/v1/verification/nin', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'app-id': appId,
        'x-api-key': apiKey,
      },
      body: JSON.stringify({ number }),
    });

    // Get the response data
    const data = await premblyResponse.json();

    // Return the response with appropriate status code
    return NextResponse.json(data, { status: premblyResponse.status });
  } catch (error) {
    // Handle any errors
    console.error('Error verifying NIN:', error);
    return NextResponse.json(
      { error: 'Internal server error', message: error.message },
      { status: 500 }
    );
  }
}

